const AWS = require('aws-sdk');
const childProcess = require('child_process');

exports.handler = async (event) => {
  const s3Event = event.Records[0].s3;
  const imageKey = s3Event.object.key;
  const outputFormat = s3Event.object.metadata.output_format;

  if (!imageKey || !outputFormat) {
    throw new Error('Missing required parameters');
  }

  try {
    const convertCommand = `convert ${imageKey} -format ${outputFormat} output.jpg`;
    childProcess.execSync(convertCommand, { stdio: 'inherit' });
  } catch (error) {
    console.error(error);
    throw error;
  }

  return {
    statusCode: 200,
    statusMessage: 'Image converted successfully',
  };
};